class Solution {
    public int minAddToMakeValid(String s) {
        int count = 0;
        int balance = 0;
        for (char c : s.toCharArray()) {
            if (c == '(') {
                balance++;
            } else {
                balance--;
            }
            if (balance < 0) {
                count++;
                balance = 0;
            }
        }
        return count + balance;
    }
}
